class Solution:
    def findMaximumPairs(self, students: str) -> int:
        total_students = len(students)
        if total_students == 0:
            return 0

        dp = [0] * total_students

        for i in range(1, total_students):
            if students[i] == students[i - 1]:
                dp[i] = dp[i - 1]
            else:
                dp[i] = max(dp[i - 1], (dp[i - 2] + 1) if i >= 2 else 1)

        return dp[total_students - 1]

