int findMaximumPairs(Solution *sol, char students[]) {
    int totalStudents = strlen(students);

    sol->dp[0] = 0;

    for (int i = 1; i < totalStudents; i++) {
        if (students[i] == students[i - 1]) {
            sol->dp[i] = sol->dp[i - 1];
        } else {
            sol->dp[i] = (i >= 2) ? sol->dp[i - 2] + 1 : 1;
            if (sol->dp[i - 1] > sol->dp[i]) {
                sol->dp[i] = sol->dp[i - 1];
            }
        }
    }

    return sol->dp[totalStudents - 1];
}

code.Java:
class Solution {
    public int findMaximumPairs(String s) {
        int c = 0;
        for (int i = 0; i < s.length(); i++) {
            if (i > 0) {
                if ((s.charAt(i) == 'x' && s.charAt(i - 1) == 'y') ||
                    (s.charAt(i) == 'y' && s.charAt(i - 1) == 'x')) {
                    c++;
                    i++; // skip next character
                }
            }
        }
        return c;
    }
}

